mapper.select:
    	/* com.erns.coching.partner.mapper.PartnerDAO.getList */

    	SELECT B.* FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() AS TOTAL FROM (
					SELECT

				    FROM  T_PARTNER_INF AA



			) A
		) B

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

mapper.insert:
    	/* com.erns.coching.partner.mapper.PartnerDAO.insert */


			SELECT nextval('seq_t_partner_inf')


    	INSERT INTO T_PARTNER_INF (
    		  PTN_SEQ
			, PTN_NAME
			, NATION
			, PTN_LIC
			, PAGE_URL
			, LOGO_FILE_ID
			, DEL_YN
			, RGTR
			, RGT_DTTM
    	) VALUES (
			  #{ptnSeq		, jdbcType=INTEGER}
			, #{ptnName		, jdbcType=VARCHAR}
			, #{nation		, jdbcType=VARCHAR}
			, #{ptnLic	, jdbcType=VARCHAR}
			, #{pageUrl	, jdbcType=VARCHAR}
			, #{logoFileId	, jdbcType=VARCHAR}
			, COALESCE(#{delYn	, jdbcType=CHAR}, 'N')
			, #{rgtr		, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
    	/* com.erns.coching.partner.mapper.PartnerDAO.update */

    	UPDATE T_PARTNER_INF SET
			  PTN_NAME       	= #{ptnName	, jdbcType=VARCHAR}
			, NATION        	= #{nation	, jdbcType=VARCHAR}
			, PTN_LIC        	= #{ptnLic	, jdbcType=VARCHAR}
			, PAGE_URL          = #{pageUrl		, jdbcType=VARCHAR}
			, LOGO_FILE_ID      = #{logoFileId	, jdbcType=VARCHAR}
			, DEL_YN        	= #{delYn	, jdbcType=VARCHAR}

			, CHNR 		 		= #{chnr, jdbcType=INTEGER}
			, CHNG_DTTM  		= now()

			AND PTN_SEQ 		= #{ptnSeq	, jdbcType=INTEGER}

    	/* com.erns.coching.partner.mapper.PartnerDAO.updateDelYn */

    	UPDATE T_PARTNER_INF SET
			  DEL_YN        = COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 	= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  	= now()

			AND PTN_SEQ 	= #{ptnSeq	, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.partner.mapper.PartnerDAO.delete */

DELETE FROM T_PARTNER_INF

	AND PTN_SEQ 	= #{ptnSeq	, jdbcType=INTEGER}
